import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';
import './index.css';

const init = () => {
  const rootElement = document.getElementById('root');
  if (rootElement) {
    const root = ReactDOM.createRoot(rootElement);
    root.render(
      <React.StrictMode>
        <App />
      </React.StrictMode>
    );
  } else {
    setTimeout(init, 10);
  }
};

init();
